import React, { useEffect, useState } from "react";
import Input from "../../components/Input";
import Button from "../../components/Button";
import dft from "../../images/default.jpeg";
import logo from "../../images/logotalkies.png";
import { Link, useNavigate } from "react-router-dom";
import {
  IconBookmark,
  IconHeart,
  IconLogout,
  IconMessage,
  IconPlus,
  IconSearch,
  IconShare,
} from "@tabler/icons-react";
import { navigations, stats } from "./data";
import { GridLoader } from "react-spinners";
const Home = () => {
  const navigate = useNavigate();
  const [commentOn, setcommentOn] = useState(false);
  const [data, setdata] = useState([]);
  const [User, setUser] = useState({});
  const [loading, setloading] = useState(false);
  const [msg, setmsg] = useState("");
  const [search, setsearch] = useState("");
  useEffect(() => {
    const fetchPosts = async () => {
      setloading(true);
      const response = await fetch("http://localhost:8000/api/posts", {
        method: "GET",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
      });
      const data1 = await response.json();
      console.log(data1);
      setdata(data1.post1);
      console.log(data);
      setUser(data1.user);
      setloading(false);
    };
    fetchPosts();
  }, []);
  const handleSearch = async () => {
    try {
      const response = await fetch("http://localhost:8000/api/search", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
        body: JSON.stringify({ search: search }),
      });
      const res = await response.json();
      if (response.status === 200) {
        navigate("/search", {
          state: {
            userFromUserName: res.usersFromUserName,
            userFromEmail: res.usersFromEmail,
          },
        });
      }
      console.log(res);
    } catch (error) {
      console.log(error);
    }
  };
  const handleSaves = async (_id, index) => {
    try {
      const response = await fetch("http://localhost:8000/api/save", {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
        body: JSON.stringify({ id: _id }),
      });
      const updatedPost = await response.json();
      const updatePost = data?.map((post, i) => {
        if (i === index) return updatedPost;
        else return post;
      });
      setdata(updatePost);
    } catch (error) {
      console.log(error);
    }
  };
  const handleUnsaves = async (_id, index) => {
    try {
      const response = await fetch("http://localhost:8000/api/Unsave", {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
        body: JSON.stringify({ id: _id }),
      });
      const updatedPost = await response.json();
      const updatePost = data?.map((post, i) => {
        if (i === index) return updatedPost;
        else return post;
      });
      setdata(updatePost);
    } catch (error) {
      console.log(error);
    }
  };
  const handleComment = async (_id, index, msg) => {
    try {
      const response = await fetch("http://localhost:8000/api/comment", {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
        body: JSON.stringify({ id: _id, message: msg }),
      });
      const updatedPost = await response.json();
      const updatePost = data?.map((post, i) => {
        if (i === index) return updatedPost;
        else return post;
      });
      setdata(updatePost);
    } catch (error) {
      console.log(error);
    }
  };
  const handleLike = async (_id, index) => {
    try {
      const response = await fetch("http://localhost:8000/api/like", {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
        body: JSON.stringify({ id: _id }),
      });
      const updatedPost = await response.json();
      const updatePost = data?.map((post, i) => {
        if (i === index) return updatedPost;
        else return post;
      });
      setdata(updatePost);
    } catch (error) {
      console.log(error);
    }
  };
  const handleUnlike = async (_id, index) => {
    const response = await fetch("http://localhost:8000/api/unlike", {
      method: "PUT",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${localStorage.getItem("user:token")}`,
      },
      body: JSON.stringify({ id: _id }),
    });
    const updatedPost = await response.json();
    const updatePost = data?.map((post, i) => {
      if (i === index) return updatedPost;
      else return post;
    });
    setdata(updatePost);
  };
  const {
    userName = "",
    follower = [],
    following = [],
    posts = [],
  } = User || {};
  return (
    <div className="h-screen flex overflow-hidden">
      <div className="w-[20%] flex flex-col bg-[#dde3f6]">
        {loading ? (
          <div className="h-[100%] flex justify-center items-center">
            <GridLoader />
          </div>
        ) : (
          <div className="h-[30%] flex justify-center items-center border-b">
            <div className="flex flex-col justify-center items-center">
              <div className="flex my-4">
                <img
                  src={User?.profilePic || dft}
                  alt="Profile"
                  className="w-[25%] mx-6 rounded-full"
                />
                <div className="flex flex-col">
                  <p className="mt-4 mb-0 pb-0 text-xl font-bold">
                    {User.userName}
                  </p>
                  <p className="text-xs mb-4 font-semibold">{User.email}</p>
                </div>
              </div>
              <div
                className="h-[50px] flex justify-around w-[300px] text-center cursor-pointer"
                onClick={() => navigate("/followers")}
              >
                <div className="font-light text-lg">
                  <h4>{follower.length}</h4>
                  <p>Followers</p>
                </div>
                <div className="font-light text-lg">
                  <h4>{following.length}</h4>
                  <p>Following</p>
                </div>
                <div className="font-light text-lg">
                  <h4>{posts.length}</h4>
                  <p>Posts</p>
                </div>
              </div>
            </div>
          </div>
        )}
        <div className="h-[55%] flex flex-col justify-evenly pl-12 border-b">
          {navigations.map(({ id, name, icon, url }) => {
            return (
              <Link
                to={url}
                key={id}
                className="text-gray-500 flex hover:text-black"
              >
                {icon}
                <p className="ml-2">{name}</p>
                {id === 2 && User.followRequest?.length > 0 && (
                  <p className="text-gray-500 flex hover:text-black bg-[#ff0000] rounded-full w-[25px] flex justify-center align-items ">
                    {User.followRequest.length}
                  </p>
                )}
              </Link>
            );
          })}
        </div>
        <div className="h-[15%] pt-10">
          <div
            className="ml-12 cursor-pointer flex text-gray-500 flex hover:text-black"
            onClick={() => {
              localStorage.clear();
              navigate("/account/signin");
            }}
          >
            <IconLogout />
            <p className="ml-2 ">Log out</p>
          </div>
        </div>
      </div>
      <div className="w-[60%] h-full overflow-scroll scrollbar-hide">
        <div className="h-[75px] bg-white border-l flex justify-center items-center sticky top-0 shadow-md">
          <div className="flex justify-center items-center">
            <Input
              placeholder="Search"
              className="rounded-3xl"
              value={search}
              onChange={(e) => {
                setsearch(e.target.value);
              }}
            />
            <Button
              label={<IconSearch />}
              className="mb-4 ml-4 rounded-3xl mr-20 bg-[#8d91f4] hover:bg-[#525197]"
              onChange={() => {
                handleSearch();
              }}
            ></Button>
          </div>
          <Button
            label={
              <div className="flex">
                <IconPlus />
                <p className="ml-2">Create New Post</p>
              </div>
            }
            className="rounded-3xl mb-4 ml-15 bg-[#8d91f4] hover:bg-[#525197]"
            onChange={() => {
              navigate("/new-post");
            }}
          ></Button>
        </div>
        {loading ? (
          <div className="h-[100%] flex justify-center items-center">
            <GridLoader />
          </div>
        ) : (
          data?.map(
            (
              {
                _id = "",
                caption = "",
                description = "",
                image = "",
                user = {},
                likes = [],
                comment = [],
                save = [],
                isVideo = false,
              },
              index
            ) => {
              const isAlreadyLiked =
                likes.length > 0 && likes.includes(User._id);
              return (
                <div className="bg-white w-[75%] mx-auto mt-20 p-8">
                  <div
                    className="border-b flex items-center pb-4 mb-4 cursor-pointer"
                    onClick={() =>
                      userName === user.userName
                        ? navigate("/profile")
                        : navigate(`/user/${user?.userName}`)
                    }
                  >
                    <div className="flex my-4">
                      <img
                        src={user?.profilePic || dft}
                        alt="Profile"
                        className="w-[17%] mx-6 rounded-full"
                      />
                      <div className="flex flex-col">
                        <p className="mt-4 mb-0 pb-0 text-xl font-bold">
                          {user.userName}
                        </p>
                        <p className="text-xs mb-4 font-semibold">
                          {user.email}
                        </p>
                      </div>
                    </div>
                  </div>
                  <div className="border-b pb-4 mb-4 flex flex-col justify-center items-center h-[75%] mt-9">
                    {isVideo ? (
                      <video
                        autoplay
                        controls
                        className="w-[100%] m-0 p-0 rounded-2xl"
                      >
                        <source src={image}></source>
                      </video>
                    ) : (
                      <img
                        src={image}
                        alt="Post"
                        className="w-[100%] m-0 p-0 rounded-2xl"
                      />
                    )}
                    <div className="flex mt-4 mb-2 pb-2 border-b">
                      <h4 className="mr-4 font-bold">{user.email}:</h4>
                      <p className="font-medium">{caption}</p>
                    </div>
                    <p className="mt-3">{description}</p>
                  </div>
                  <div className="flex justify-evenly border-b mb-4 pb-3">
                    <div
                      className="flex cursor-pointer "
                      onClick={
                        isAlreadyLiked
                          ? () => handleUnlike(_id, index)
                          : () => handleLike(_id, index)
                      }
                    >
                      <IconHeart
                        fill={isAlreadyLiked ? "red" : "white"}
                        color={isAlreadyLiked ? "red" : "black"}
                      />
                      <p>{likes?.length}</p>
                    </div>
                    <div
                      className="flex cursor-pointer"
                      onClick={() => {
                        setcommentOn(!commentOn);
                      }}
                    >
                      <IconMessage />
                      <p>{comment?.length}</p>
                    </div>
                    <div className="flex">
                      <IconShare />
                      10.5K Shares
                    </div>
                    <div
                      className="flex cursor-pointer"
                      onClick={() => {
                        save.length > 0 && save.includes(User._id)
                          ? handleUnsaves(_id, index)
                          : handleSaves(_id, index);
                      }}
                    >
                      <IconBookmark
                        fill={
                          save.length > 0 && save.includes(User._id)
                            ? "blue"
                            : "white"
                        }
                        color={
                          save.length > 0 && save.includes(User._id)
                            ? "blue"
                            : "black"
                        }
                      />
                      <p>{save?.length}</p>
                    </div>
                  </div>
                  <div id="comment" className={commentOn ? "" : "hidden"}>
                    <div id="ipt" className="flex justify-center items-center">
                      <p className="font-semibold">Comment :</p>
                      <Input
                        type="text"
                        value={msg}
                        className="rounded-3xl"
                        onChange={(e) => {
                          setmsg(e.target.value);
                        }}
                      />
                      <Button
                        label="Comment"
                        className="mb-4 ml-4 rounded-3xl mr-20 bg-[#8d91f4] hover:bg-[#525197]"
                        onChange={() => {
                          handleComment(_id, index, msg);
                        }}
                      ></Button>
                    </div>
                    <div className="flex flex-col">
                      {comment?.map(({ commentUser = "", msg = "" }) => {
                        return (
                          <div className="flex w-[100%]">
                            <p className="font-semibold">{commentUser} :</p>
                            <p>{msg}</p>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>
              );
            }
          )
        )}
      </div>
      <div className="w-[20%] bg-[#f2f5f8] overflow-scroll scrollbar-hide">
        <div className="h-[30%]">
          <img src={logo} alt="Logo" className="object-contain"></img>
        </div>
        <div className="h-[55%] bg-white flex flex-col justify-evenly pl-12 border-b">
          {stats.map(({ id, name, icon, url }) => {
            return (
              <Link
                to={url}
                key={id}
                className="text-gray-500 flex hover:text-black"
              >
                {icon}
                <p className="ml-2">{name}</p>
              </Link>
            );
          })}
        </div>
        <div className="h-[15%] bg-white pt-10">
          <div
            className="ml-12 cursor-pointer flex text-gray-500 flex hover:text-black"
            onClick={() => {
              localStorage.clear();
              navigate("/account/signup");
            }}
          >
            <IconLogout />
            <p className="ml-2 ">Sign out</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Home;
